#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e4+10;
int n,m,b,f[MAXN],d[MAXN];
char w[MAXN];
vector<PII> g[MAXN];
bool check(int u)
{
    cli(d);
    cl(w);
    d[1]=0;
    priority_queue<PII,vector<PII>,greater<>> q;
    q.push(mk(0,1));
    while(!q.empty())
	{
        PII cur=q.top();
		q.pop();
        int dd=cur.fst,x=cur.snd;
        if(w[x]||f[x]>u)
		{
			continue;
		}
        if(dd!=d[x])
		{
			continue;
		}
        w[x]=1;
        FOI(e,g[x])
		{
            int y=e.fst,z=e.snd;
            if(f[y]>u)
			{
				continue;
			}
            if(d[y]>d[x]+z)
			{
                d[y]=d[x]+z;
                q.push(mk(d[y],y));
            }
        }
    }
    return d[n]<=b;
}
signed main(void)
{
    n=read(),m=read(),b=read();
    FOR(i,1,n)
	{
		f[i]=read();
	}
    FOR(i,1,m)
	{
        int u=read(),v=read(),c=read();
        g[u].push_back(mk(v,c));
        g[v].push_back(mk(u,c));
    }
    int l=0,r=1e9,a=-1;
    wh(l<=r)
	{
        if(check(mid))a=mid,r=mid-1;
        else l=mid+1;
    }
    if(a==-1)puts("AFK");
    else write(a);
    return false;
}
